code = """import json
import pandas as pd

# Get the closed cases from the database query
closed_cases = locals()['var_functions.query_db:24']

# Create DataFrame
df_cases = pd.DataFrame(closed_cases)

print('Original closed cases count:', len(df_cases))
print(df_cases)

# Clean IDs
def clean_id(id_str):
    if id_str and isinstance(id_str, str):
        return id_str.replace('#', '').strip()
    return id_str

df_cases['id'] = df_cases['id'].apply(clean_id)
df_cases['ownerid'] = df_cases['ownerid'].apply(clean_id)

# Group by agent to see case counts
agent_counts = df_cases.groupby('ownerid').size().reset_index(name='case_count')
print('Agent case counts:')
print(agent_counts)

# Now load case history to check for transfers
file_path = locals()['var_functions.query_db:6']
with open(file_path, 'r') as f:
    case_history = json.load(f)

df_history = pd.DataFrame(case_history)

# Clean history data
df_history['caseid__c'] = df_history['caseid__c'].apply(clean_id)
df_history['newvalue__c'] = df_history['newvalue__c'].apply(clean_id)

# Get history for our closed cases
case_ids = df_cases['id'].tolist()
df_relevant_history = df_history[df_history['caseid__c'].isin(case_ids)]

# Count unique agents per case (identifies transfers)
case_transfers = df_relevant_history.groupby('caseid__c')['newvalue__c'].nunique().reset_index()
case_transfers.columns = ['case_id', 'agent_count']

print('Case transfer analysis:')
print(case_transfers)

# Non-transferred cases (agent_count == 1)
non_transferred = case_transfers[case_transfers['agent_count'] == 1]['case_id'].tolist()

print('Non-transferred case IDs:', non_transferred)
print('Count:', len(non_transferred))

result = {"agent_ids": list(agent_counts[agent_counts['case_count'] > 1]['ownerid'].unique())}

print('__RESULT__:')
print(json.dumps(result))"""

